  #{vcFactRetype,jdbcType=CHAR}, #{lExecOrder,jdbcType=DECIMAL}, #{cResIsCondition,jdbcType=CHAR}, 
  #{cExpressType,jdbcType=CHAR}, #{vcExpress,jdbcType=VARCHAR}, #{cOptimize,jdbcType=CHAR}
  )

